# WebSocket server
def generate_websocket_key(key):
    GUID = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
    key = key + GUID
    key = key.encode()
    sha1 = hashlib.sha1(key)
    return ubinascii.b2a_base64(sha1.digest())[:-1].decode()

def handle_websocket_connection(client_socket):
    try:
        # Read HTTP request
        request = client_socket.recv(1024).decode()
        
        # Extract WebSocket key
        key = None
        for line in request.split('\n'):
            if line.startswith('Sec-WebSocket-Key:'):
                key = line.split()[1]
                break
        
        if not key:
            client_socket.close()
            return
        
        # Generate WebSocket accept key
        accept_key = generate_websocket_key(key)
        
        # Send WebSocket upgrade response
        response = (
            "HTTP/1.1 101 Switching Protocols\r\n"
            "Upgrade: websocket\r\n"
            "Connection: Upgrade\r\n"
            "Sec-WebSocket-Accept: " + accept_key + "\r\n\r\n"
        )
        client_socket.send(response.encode())
        
        # Handle WebSocket messages
        while True:
            try:
                # Receive WebSocket frame
                data = client_socket.recv(1024)
                if not data:
                    break
                
                # Parse WebSocket frame (simplified)
                if len(data) > 2:
                    # Check if it's a text frame
                    if data[0] & 0x80 == 0x80 and data[1] & 0x7F != 0:
                        # Extract payload
                        payload_len = data[1] & 0x7F
                        payload_start = 2
                        if payload_len == 126:
                            payload_len = int.from_bytes(data[2:4], 'big')
                            payload_start = 4
                        elif payload_len == 127:
                            payload_len = int.from_bytes(data[2:10], 'big')
                            payload_start = 10
                        
                        payload = data[payload_start:payload_start + payload_len]
                        
                        # Try to parse JSON
                        try:
                            message = ujson.loads(payload.decode())
                            print("Received message:", message)
                            
                            # Handle commands
                            if "action" in message:
                                if message["action"] == "turn_on":
                                    print("Turning on device")
                                    # Add your device control logic here
                                elif message["action"] == "turn_off":
                                    print("Turning off device")
                                    # Add your device control logic here
                                
                        except Exception as e:
                            print("JSON parsing error:", e)
                
            except Exception as e:
                print("WebSocket error:", e)
                break
                
    except Exception as e:
        print("Connection error:", e)
    finally:
        client_socket.close()

# Start server
def start_websocket_server():
    # Create socket
    server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    server_socket.bind(('0.0.0.0', 80))
    server_socket.listen(5)
    
    print("WebSocket server listening on port 80")
    
    while True:
        try:
            client_socket, addr = server_socket.accept()
            print("Connection from:", addr)
            handle_websocket_connection(client_socket)
        except Exception as e:
            print("Server error:", e)
            continue

# Start the server
start_websocket_server()